interval_in_ms = 1
number_of_requests = 30

def main():    
    # Create the request
    request = pb2.ProveTransactionRequest(transaction_witness=bytes(byte_array))

    # Establish a gRPC channel
    with grpc.insecure_channel("0.0.0.0:8082") as channel:
        # Create a stub (client)
        stub = pb2_grpc.ApiStub(channel)

        current_requests_number = 0
        while True:
            # Break if the number of requests is reached
            if current_requests_number >= number_of_requests:
                break

            # Make the gRPC call
            try:
                stub.ProveTransaction(request)
            except grpc.RpcError as e:
                print(f"gRPC failed with {e.code()}: {e.details()}")
            
            # Sleep for the interval
            # time.sleep(interval_in_ms / 1000)
            current_requests_number += 1

if __name__ == "__main__":
    main()

